-- Auto-generated from seed_profiles.json
-- Aligns legacy profiles table to Stage 2 schema and seeds idempotently
BEGIN;

-- 1) Ensure Stage 2 columns exist.
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS country_name varchar;

-- 2) Normalize existing data before constraints.
UPDATE public.profiles
SET
    name = trim(name),
    gender = lower(trim(gender)),
    age_group = lower(trim(age_group)),
    country_id = upper(left(trim(country_id), 2)),
    country_name = COALESCE(NULLIF(trim(country_name), ''), upper(left(trim(country_id), 2)));

-- 3) Remove duplicate names (case-insensitive), keep first row.
WITH ranked AS (
    SELECT ctid, row_number() OVER (PARTITION BY lower(trim(name)) ORDER BY ctid) AS rn
    FROM public.profiles
)
DELETE FROM public.profiles p
USING ranked r
WHERE p.ctid = r.ctid
  AND r.rn > 1;

-- 4) Convert id to UUID when legacy schema uses text.
DO $$
DECLARE
    id_data_type text;
    pk_name text;
BEGIN
    SELECT data_type INTO id_data_type
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'profiles' AND column_name = 'id';

    IF id_data_type IS DISTINCT FROM 'uuid' THEN
        ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS id_uuid uuid;
        UPDATE public.profiles
        SET id_uuid = CASE
            WHEN id ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-8][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$' THEN id::uuid
            ELSE gen_random_uuid()
        END
        WHERE id_uuid IS NULL;

        SELECT tc.constraint_name INTO pk_name
        FROM information_schema.table_constraints tc
        WHERE tc.table_schema = 'public' AND tc.table_name = 'profiles' AND tc.constraint_type = 'PRIMARY KEY' LIMIT 1;

        IF pk_name IS NOT NULL THEN
            EXECUTE format('ALTER TABLE public.profiles DROP CONSTRAINT %I', pk_name);
        END IF;

        ALTER TABLE public.profiles DROP COLUMN id;
        ALTER TABLE public.profiles RENAME COLUMN id_uuid TO id;
    END IF;
END $$;

-- 5) Convert created_at to TIMESTAMP when legacy schema uses text.
DO $$
DECLARE
    created_at_data_type text;
BEGIN
    SELECT data_type INTO created_at_data_type
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'profiles' AND column_name = 'created_at';

    IF created_at_data_type IN ('text', 'character varying') THEN
        UPDATE public.profiles
        SET created_at = to_char((now() at time zone 'utc'), 'YYYY-MM-DD HH24:MI:SS')
        WHERE created_at IS NULL OR btrim(created_at) = '';

        ALTER TABLE public.profiles
            ALTER COLUMN created_at TYPE timestamp without time zone
            USING replace(replace(created_at, 'T', ' '), 'Z', '')::timestamp;
    END IF;
END $$;

-- 6) Drop legacy Stage 1 columns if present.
ALTER TABLE public.profiles
    DROP COLUMN IF EXISTS normalized_name,
    DROP COLUMN IF EXISTS sample_size,
    DROP COLUMN IF EXISTS normalized_gender,
    DROP COLUMN IF EXISTS normalized_age_group,
    DROP COLUMN IF EXISTS normalized_country_id;

-- 7) Enforce exact Stage 2 column types/constraints.
ALTER TABLE public.profiles
    ALTER COLUMN id TYPE uuid USING id::uuid,
    ALTER COLUMN name TYPE varchar USING name::varchar,
    ALTER COLUMN gender TYPE varchar USING gender::varchar,
    ALTER COLUMN gender_probability TYPE double precision USING gender_probability::double precision,
    ALTER COLUMN age TYPE integer USING age::integer,
    ALTER COLUMN age_group TYPE varchar USING age_group::varchar,
    ALTER COLUMN country_id TYPE varchar(2) USING upper(left(country_id, 2)),
    ALTER COLUMN country_name TYPE varchar USING country_name::varchar,
    ALTER COLUMN country_probability TYPE double precision USING country_probability::double precision,
    ALTER COLUMN created_at TYPE timestamp without time zone USING created_at::timestamp;

ALTER TABLE public.profiles
    ALTER COLUMN id SET NOT NULL,
    ALTER COLUMN name SET NOT NULL,
    ALTER COLUMN gender SET NOT NULL,
    ALTER COLUMN gender_probability SET NOT NULL,
    ALTER COLUMN age SET NOT NULL,
    ALTER COLUMN age_group SET NOT NULL,
    ALTER COLUMN country_id SET NOT NULL,
    ALTER COLUMN country_name SET NOT NULL,
    ALTER COLUMN country_probability SET NOT NULL,
    ALTER COLUMN created_at SET NOT NULL,
    ALTER COLUMN created_at SET DEFAULT (now() at time zone 'utc');

ALTER TABLE public.profiles DROP CONSTRAINT IF EXISTS profiles_pkey;
ALTER TABLE public.profiles ADD CONSTRAINT profiles_pkey PRIMARY KEY (id);
ALTER TABLE public.profiles DROP CONSTRAINT IF EXISTS profiles_name_key;
ALTER TABLE public.profiles ADD CONSTRAINT profiles_name_key UNIQUE (name);
ALTER TABLE public.profiles DROP CONSTRAINT IF EXISTS profiles_gender_check;
ALTER TABLE public.profiles ADD CONSTRAINT profiles_gender_check CHECK (gender IN ('male', 'female'));
ALTER TABLE public.profiles DROP CONSTRAINT IF EXISTS profiles_age_group_check;
ALTER TABLE public.profiles ADD CONSTRAINT profiles_age_group_check CHECK (age_group IN ('child', 'teenager', 'adult', 'senior'));

-- Prefer UUID v7 generator when available.
DO $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM pg_proc
        WHERE proname = 'uuid_generate_v7'
    ) THEN
        ALTER TABLE public.profiles ALTER COLUMN id SET DEFAULT uuid_generate_v7();
    ELSE
        ALTER TABLE public.profiles ALTER COLUMN id SET DEFAULT gen_random_uuid();
    END IF;
END $$;

